public class PatternDetectionUtil {
  public static boolean isNumeric(String pattern) {
    for (int i = 0; i < pattern.length(); i++) {
      if (!(Character.isDigit(pattern.charAt(i)))) {
        return false;
      }
    }
    return pattern.length() > 0;
  }
}
